#include <bits/stdc++.h>
using namespace std;

int main() {
    string n;
    int k, t;
    cin >> n >> k;
    n += '/';
    for (int i = 0; i < k; i++) {
        for (int j = 0; j < n.size() - 1; j++) {
            if (n[j] > n[j + 1]) {
                n.erase(n.begin() + j);
                break;
            }
        }
    }
    n[n.size() - 1] = '\0';
    while (n[0] == '0' && n.size() > 2) {
        n.erase(n.begin());
    }
    cout << n;
    return 0;
}
